func TestFind(t *testing.T) {
    tests := []struct {
        full string
        part string
        want int
    }{
        {"Dr John", "salutation", 0},
        {"John Jr Doe", "generation", 1},
        {"John PhD Smith", "suffix", 1},
        {"de la Rosa", "lnprefix", 0},
        {"John aka Doe", "nonname", 1},
        {"Alice Foo", "foo", -1},
    }
    for _, tc := range tests {
        n := nameString{FullName: tc.full}
        got := n.find(tc.part)
        if got != tc.want {
            t.Errorf("find(%q) on %q = %d; want %d", tc.part, tc.full, got, tc.want)
        }
    }
}

