package gonameparts

import (
   "strings"
   "testing"
)

func TestSplitAliases(t *testing.T) {
   tests := []struct {
       full       string
       aliasSep   string
       wantFull   string
       wantAliases []string
   }{
       {"Foo ALIAS Bar Baz", "ALIAS", "Foo", []string{"Bar Baz"}},
       {"One alias two Alias Three Four", "ALIAS", "One", []string{"two", "Three Four"}},
       {"Foo Bar Baz", "ALIAS", "Foo Bar Baz", nil},
   }
   for _, tt := range tests {
       n := &nameString{FullName: tt.full}
       n.splitAliases(tt.aliasSep)
       gotFull := strings.TrimSpace(n.FullName)
       if gotFull != tt.wantFull {
           t.Errorf("FullName = %q; want %q", gotFull, tt.wantFull)
       }
       if len(n.Aliases) != len(tt.wantAliases) {
           t.Errorf("Aliases length = %d; want %d", len(n.Aliases), len(tt.wantAliases))
           continue
       }
       for i, want := range tt.wantAliases {
           if strings.TrimSpace(n.Aliases[i]) != want {
               t.Errorf("Aliases[%d] = %q; want %q", i, strings.TrimSpace(n.Aliases[i]), want)
           }
       }
   }
}

