pub fn parse(name: &str) -> NameParts {
    let mut n = NameString { full_name: name.to_string(), ..Default::default() };
    n.normalize().expect("normalize failed");

    let mut p = NameParts { provided_name: name.to_string(), nickname: n.nickname.clone(), ..Default::default() };
    if n.looks_corporate() { return p; }

    let parts = ["generation", "suffix", "lnprefix", "supplemental"];
    let mut part_map: HashMap<&str, i32> = HashMap::new();
    let mut slotted: Vec<usize> = Vec::new();

    for &part in &parts {
        let idx = n.find(part).unwrap_or(-1);
        part_map.insert(part, idx);
        if idx > -1 {
            p.slot(part, &n.split_name[idx as usize]);
            slotted.push(idx as usize);
        }
    }

    if let Ok(sal) = n.find("salutation") {
        if sal == 0 { part_map.insert("salutation", sal); p.slot("salutation", &n.split_name[sal as usize]); slotted.push(sal as usize); } else { part_map.insert("salutation", -1); }
    } else { part_map.insert("salutation", -1); }

    if let Ok(nn) = n.find("nonname") {
        if nn > -1 && (nn as usize) < n.split_name.len()-1 { part_map.insert("nonname", nn); p.slot("nonname", &n.split_name[nn as usize]); slotted.push(nn as usize); } else { part_map.insert("nonname", -1); }
    } else { part_map.insert("nonname", -1); }

    let first_pos = *part_map.get("salutation").unwrap_or(&-1) + 1;
    if first_pos == n.split_name.len() as i32 { p.build_full_name().unwrap(); return p; }
    part_map.insert("first", first_pos);
    p.slot("first", &n.split_name[first_pos as usize]); slotted.push(first_pos as usize);

    if let Some(&ln_prefix) = part_map.get("lnprefix") {
        if ln_prefix > -1 {
            let mut ln_end = n.split_name.len();
            if let Some(&gen) = part_map.get("generation") { if gen > -1 { ln_end = gen as usize; } }
            if let Some(&sfx) = part_map.get("suffix") { if sfx > -1 && (sfx as usize) < ln_end { ln_end = sfx as usize; } }
            if ln_end > ln_prefix as usize {
                let last_name = n.split_name[ln_prefix as usize..ln_end].join(" ");
                p.slot("last", &last_name);
            }
            for i in ln_prefix as usize..=ln_end { slotted.push(i); }
        }
    }

    let not_slotted = n.find_not_slotted(&slotted).unwrap();
    if not_slotted.len() > 1 {
        let ln_prefix = *part_map.get("lnprefix").unwrap_or(&-1);
        let mut multi_middle = Vec::new();
        if ln_prefix > -1 {
            // Replicate Go bug: iterate over slice indices
            for idx in 0..not_slotted.len() {
                multi_middle.push(n.split_name[idx].clone());
            }
            p.slot("middle", &multi_middle.join(" "));
        } else {
            let mut tmp = not_slotted.clone(); tmp.sort(); let last_i = *tmp.last().unwrap();
            p.slot("last", &n.split_name[last_i]);
            for &i in &not_slotted {
                if i != last_i { multi_middle.push(n.split_name[i].clone()); }
            }
            p.slot("middle", &multi_middle.join(" "));
        }
    } else if not_slotted.len() == 1 {
        if *part_map.get("lnprefix").unwrap_or(&-1) > -1 { p.slot("middle", &n.split_name[not_slotted[0]]); }
        else { p.slot("last", &n.split_name[not_slotted[0]]); }
    }

    for alias in &n.aliases { p.aliases.push(parse(alias).unwrap()); }
    p.build_full_name().unwrap();
    p
}
